mapper.select:
SELECT id, chat_id AS chatId, msg_id AS msgId, from_wecom_userid AS fromWecomUserid, raw_message AS rawMessage, status, parse_type AS parseType, nlp_confidence AS nlpConfidence, ticket_id AS ticketId, error_msg AS errorMsg, create_time AS createTime FROM wecom_bot_message_log WHERE deleted = 0
AND parse_type = #{input.parseType}
AND chat_id = #{input.chatId}
AND from_wecom_userid = #{input.fromWecomUserid}
AND nlp_confidence >= #{input.minConfidence}
AND create_time >= #{input.startTime}
AND create_time <= #{input.endTime}
ORDER BY create_time DESC
